#include <stdbool.h>
#include <stdio.h>

int main(void) {
    int quantity;
    double price;
    if (scanf("%d %lf", &quantity, &price) != 2) return 1;
    bool active = quantity != 0;
    printf("%s %.2f\n", active ? "active" : "inactive", quantity * price);
    return 0;
}
